using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

// ── Configuration ──────────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_CHAT_MODEL") ?? "gpt-4o";

// ── Chat client with automatic function-calling ────────────────────────────────
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var notebook = new Notebook();

IChatClient client = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(SearchWeb, "search_web"),
        AIFunctionFactory.Create(notebook.TakeNote, "take_note"),
        AIFunctionFactory.Create(notebook.GetNotes, "get_notes"),
    ]
};

// ── System prompt ──────────────────────────────────────────────────────────────
var history = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a thorough research agent. When the user provides a topic:
        1. Use search_web multiple times with varied queries to gather broad information.
        2. Use take_note to record every key finding as you go.
        3. Once you have enough material, use get_notes to review everything.
        4. Produce a well-structured summary with sections, key takeaways, and source context.
        Be thorough but concise. Always search before answering.
        """)
};

// ── Interactive loop ───────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research.          ║");
Console.WriteLine("║  Type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research> ");
    Console.ResetColor();

    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input)) continue;
    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase)) break;

    notebook.Clear();
    history.Add(new(ChatRole.User, input));

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching… (the agent will search the web and take notes)\n");
    Console.ResetColor();

    try
    {
        var response = await client.GetResponseAsync(history, chatOptions);

        foreach (var msg in response.Messages)
            history.Add(msg);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine(response.Text);
        Console.ResetColor();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine();
}

Console.WriteLine("Goodbye!");

// ── Web search tool ────────────────────────────────────────────────────────────
[Description("Search the web for a query and return the top result snippets.")]
async Task<string> SearchWeb(
    [Description("The search query string")] string query)
{
    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine($"  🔎 Searching: {query}");
    Console.ResetColor();

    try
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = await httpClient.GetStringAsync(url);

        var snippets = new StringBuilder();
        var results = Regex.Matches(
            html,
            @"<a[^>]+class=""result__a""[^>]*>(?<title>.*?)</a>" +
            @".*?<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
            RegexOptions.Singleline);

        var count = 0;
        foreach (Match match in results)
        {
            if (count >= 6) break;
            var title = StripHtml(match.Groups["title"].Value);
            var snippet = StripHtml(match.Groups["snippet"].Value);
            if (!string.IsNullOrWhiteSpace(snippet))
            {
                snippets.AppendLine($"[{count + 1}] {title}");
                snippets.AppendLine($"    {snippet}");
                snippets.AppendLine();
                count++;
            }
        }

        return count > 0
            ? snippets.ToString()
            : "No results found. Try rephrasing the query.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

static string StripHtml(string html) =>
    Regex.Replace(
        System.Net.WebUtility.HtmlDecode(
            Regex.Replace(html, @"<[^>]+>", " ")),
        @"\s+", " ").Trim();

// ── Notebook (note-taking tool) ────────────────────────────────────────────────
class Notebook
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    [Description("Save a research note with a title and detailed content.")]
    public string TakeNote(
        [Description("Short descriptive title")] string title,
        [Description("Detailed note content")] string content)
    {
        Console.ForegroundColor = ConsoleColor.Magenta;
        Console.WriteLine($"  📝 Note saved: {title}");
        Console.ResetColor();

        _notes.Add((title, content, DateTime.UtcNow));
        return $"Note '{title}' saved ({_notes.Count} total).";
    }

    [Description("Retrieve all research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            var (t, c, ts) = _notes[i];
            sb.AppendLine($"── Note {i + 1}: {t} ({ts:HH:mm:ss UTC}) ──");
            sb.AppendLine(c);
            sb.AppendLine();
        }
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

